db.watch('orders', 'insert', (newOrder) => {
  console.log('New order inserted', newOrder.id);
  triggerNotification(newOrder);
});

def trigger_on_insert(event):
  if event.operation == 'insert':
    log_entry = {'order_id': event.new_order['id']}
    logs_collection.insert_one(log_entry)
db.listen_trigger(trigger_on_insert)

public class OrderTrigger extends AbstractEventListener {
  public void onInsert(Order order) {
    OrderLog log = new OrderLog();
    log.setOrderId(order.getId());
    logRepository.save(log);
  }
}
